<?php namespace Tests\Unit\Services; use Tests\TestCase; use App\Services\Auth\AuthService; use App\Models\User; class AuthServiceTest extends TestCase { public function test_login_requires_location() { $this->expectException(\Exception::class); $service = app(AuthService::class); $service->login('user@example.com', 'password', null, null, 'fingerprint', 'useragent'); } public function test_login_succeeds_with_valid_creds() { $user = User::create(['id' => \Illuminate\Support\Str::uuid(), 'email' => 'test@example.com', 'username' => 'testuser', 'password_hash' => \Illuminate\Support\Facades\Hash::make('password'), 'first_name' => 'Test', 'last_name' => 'User']); $service = app(AuthService::class); $result = $service->login('test@example.com', 'password', 10.0, 20.0, 'fp', 'ua'); $this->assertArrayHasKey('tokens', $result); } }
